CREATE FUNCTION dirty_pct() RETURNS DECIMAL(20,17) BEGIN DECLARE res DECIMAL(20,17); DECLARE a1, b1 VARCHAR(256); DECLARE a2, b2 VARCHAR(256); DECLARE dirty CURSOR FOR SELECT * FROM information_schema.global_status WHERE variable_name LIKE 'Innodb_buffer_pool_pages_dirty'; DECLARE total CURSOR FOR SELECT * FROM information_schema.global_status WHERE variable_name LIKE 'Innodb_buffer_pool_pages_total'; OPEN dirty; OPEN total; FETCH dirty INTO a1, b1; FETCH total INTO a2, b2; SET res = (CONVERT(b1,DECIMAL) * 100) / CONVERT(b2,DECIMAL); CLOSE dirty; CLOSE total; RETURN res; END;
